 15→func TestUploadHandler_NilStorage(t *testing.T) {
 16→	handler := uploadHandler(nil, 50<<20)
 17→
 18→	req := httptest.NewRequest(http.MethodPost, "/upload", nil)
 19→	ctx := auth.WithClaims(req.Context(), &auth.Claims{UserID: uuid.New()})
 20→	req = req.WithContext(ctx)
 21→
 22→	rr := httptest.NewRecorder()
 23→	handler.ServeHTTP(rr, req)
 24→
 25→	if rr.Code != http.StatusServiceUnavailable {
 26→		t.Errorf("expected 503, got %d", rr.Code)
 27→	}
 28→}
