 80→func TestAllowedAudioTypes(t *testing.T) {
 81→	expected := map[string]string{
 82→		"audio/mpeg":  "mp3",
 83→		"audio/wav":   "wav",
 84→		"audio/x-wav": "wav",
 85→		"audio/ogg":   "ogg",
 86→		"audio/webm":  "webm",
 87→		"audio/mp4":   "m4a",
 88→		"audio/x-m4a": "m4a",
 89→		"audio/flac":  "flac",
 90→	}
 91→
 92→	for mime, ext := range expected {
 93→		got, ok := allowedAudioTypes[mime]
 94→		if !ok {
 95→			t.Errorf("expected %q in allowedAudioTypes", mime)
 96→			continue
 97→		}
 98→		if got != ext {
 99→			t.Errorf("allowedAudioTypes[%q] = %q, want %q", mime, got, ext)
100→		}
101→	}
102→
103→	// Verify non-audio types are not allowed
104→	disallowed := []string{"text/plain", "image/png", "video/mp4", "application/pdf"}
105→	for _, mime := range disallowed {
106→		if _, ok := allowedAudioTypes[mime]; ok {
107→			t.Errorf("unexpected type %q in allowedAudioTypes", mime)
108→		}
109→	}
110→}
